// ── Utility helpers ────────────────────────────────────────

/**
 * Display a validation error beneath a form field.
 * @param {string} id  - Element ID of the error <span>
 * @param {string} msg - Error message text
 */
function setContactError(id, msg) {
  const el = document.getElementById(id);
  if (el) {
    el.textContent = msg;
    el.style.display = 'block';
  }
}

/**
 * Clear all validation errors and hide success/fail banners.
 */
function clearContactErrors() {
  document.querySelectorAll('.form-error').forEach(el => {
    el.textContent = '';
    el.style.display = 'none';
  });
  ['contact-success', 'contact-fail'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.display = 'none';
  });
}

/**
 * Basic email format check.
 * @param {string} v
 * @returns {boolean}
 */
function isEmail(v) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

// ── Form submission ────────────────────────────────────────

document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('contact-form');
  if (!form) return;
  form.addEventListener('submit', function (e) {
    e.preventDefault();
    clearContactErrors();
    let ok = true;
    const name = document.getElementById('contact-name').value.trim();
    const email = document.getElementById('contact-email').value.trim();
    const subject = document.getElementById('contact-subject').value;
    const message = document.getElementById('contact-message').value.trim();

    // Validation
    if (!name) {
      setContactError('contact-name-error', 'Your name is required.');
      ok = false;
    }
    if (!email || !isEmail(email)) {
      setContactError('contact-email-error', 'A valid email is required.');
      ok = false;
    }
    if (!subject) {
      setContactError('contact-subject-error', 'Please select a subject.');
      ok = false;
    }
    if (!message || message.length < 10) {
      setContactError('contact-message-error', 'Please enter a message (min 10 chars).');
      ok = false;
    }
    if (!ok) return;

    // Disable button while sending
    const btn = document.getElementById('contact-submit');
    btn.disabled = true;
    btn.textContent = 'Sending…';

    // ── EmailJS integration ──
    // Replace 'YOUR_PUBLIC_KEY', 'YOUR_SERVICE_ID' with your real EmailJS credentials.
    emailjs.init('YOUR_PUBLIC_KEY');
    emailjs.sendForm('YOUR_SERVICE_ID', 'template_contact', form).then(() => {
      const successEl = document.getElementById('contact-success');
      successEl.textContent = "✅ Thank you! Your message has been sent. We'll reply within 1 business day.";
      successEl.style.display = 'block';
      form.reset();
      btn.disabled = false;
      btn.textContent = 'Send Message';
      window.scrollTo({
        top: 0,
        behavior: 'smooth'
      });
    }).catch(() => {
      const failEl = document.getElementById('contact-fail');
      failEl.textContent = '❌ Something went wrong. Please email us directly at info@wellspringclinic.com.au';
      failEl.style.display = 'block';
      btn.disabled = false;
      btn.textContent = 'Send Message';
    });
  });
});

